		public boolean checkLogout() throws EncryptedDocumentException, InvalidFormatException, IOException, InterruptedException
		{
		  
			excelReader=new ExcelReader(POJOUtility.getExcelPath());
			
		  getFluentWebDriverWait().until(ExpectedConditions.elementToBeClickable(userNameDisplayLogo));
		  userNameDisplayLogo.click();
		 
		  getFluentWebDriverWait().until(ExpectedConditions.elementToBeClickable(logoutOption));
		  logoutOption.click();
		  
		  Thread.sleep(2000);
		  
		  System.out.println("Logout  Successfully");

		  getFluentWebDriverWait().until(ExpectedConditions.elementToBeClickable(username));
		  String actUserName = Boolean.toString(username.isDisplayed());
		  String expUserName = excelReader.getCellData(xlSheetName, 1003, 6); 
		  excelReader.setCellData(xlfile, xlSheetName, 1003, 7, actUserName);
				  
	      getFluentWebDriverWait().until(ExpectedConditions.elementToBeClickable(password));
	      String actPassword = Boolean.toString(password.isDisplayed());
	      String expPassword = excelReader.getCellData(xlSheetName, 1004, 6);  
	      excelReader.setCellData(xlfile, xlSheetName, 1004, 7, actPassword);
			
	      System.out.println("*************************CheckLogout***************************");
	      
	      System.out.println("UserName is Displaying : "+actUserName+"  Value Expected  "+expUserName);
	      System.out.println("Password is Displaying : "+actPassword+"  Value Expected  "+expPassword);
	      
		if(actUserName.equalsIgnoreCase(expUserName) && actPassword.equalsIgnoreCase(expPassword))  
	      {
			excelReader.setCellData(xlfile, xlSheetName, 1003, 8, resPass);
			return true;
		  }
	      else
	      {
	    	  excelReader.setCellData(xlfile, xlSheetName, 1003, 8, resFail);
	    	  return false;
		  }
	    }

		
